import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"弃牌书页包","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/弃牌/弃牌书页包.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/弃牌/弃牌书页包.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/弃牌/弃牌书页包.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"弃牌书页包",tabindex:"-1"},[p("弃牌书页包 "),r("a",{class:"header-anchor",href:"#弃牌书页包","aria-label":'Permalink to "弃牌书页包"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌036")])])],-1),n('<h1 id="弃牌书页包-1" tabindex="-1">弃牌书页包 <a class="header-anchor" href="#弃牌书页包-1" aria-label="Permalink to &quot;弃牌书页包&quot;">​</a></h1><p>弃牌书页包</p><p>【丢弃】使用具有丢弃关键词的书页时，会按照其记录的方式将对应的作战书页在二轮内弃置，这意味着你无法在二轮内使用那张书页，已被弃置的书页无法被再次弃置，若因为某些原因导致你的作战书页不足导致不能弃置，那么该书页的使用时效果将无法生效。</p><p>作战书页</p><p>爆裂打击<br> 类型：攻击技 <br> 等级：D <br> 派系：无 <br> 能耗：2点 <br> 成分：动作 <br> 动作：标准动作 <br> 射程：接触范围 <br> 持续：1轮 <br> 效果：<br> 使用时，丢弃你持有的能耗最低的作战书页，随后恢复2点光芒。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定： <br> 打击骰：若拼点成功，则此次攻击获得决心上的传奇属性*3点攻击检定上的增强加值。<br> 穿刺骰：若拼点成功，则此次攻击获得决心上的传奇属性*1点攻击检定上的附加成功。</p><p>猛烈攻势<br> 类型：攻击技 <br> 等级：D <br> 派系：无 <br> 能耗：1点 <br> 成分：动作 <br> 动作：标准动作 <br> 射程：接触范围 <br> 持续：1轮 <br> 效果：<br> 使用时，丢弃你持有的能耗最低的作战书页，<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定： <br> 穿刺骰：若拼点成功，则此次攻击获得决心上的传奇属性*2点攻击检定上的增强加值。 <br> 斩击骰：若拼点成功，则此次攻击获得决心上的传奇属性*2点攻击检定上的增强加值。<br> 穿刺骰：若拼点成功，则此次攻击获得决心上的传奇属性*1点攻击检定上的附加成功。</p><p>沉着冷静<br> 类型：攻击技 <br> 等级：C<br> 派系：无 <br> 能耗：1点 <br> 成分：动作 <br> 动作：标准动作 <br> 射程：接触范围 <br> 持续：1轮 <br> 效果：<br> 被丢弃时，获得仅能用于使用作战书页的2AP，<br> 使用时，进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 斩击骰：若拼点成功，则此次攻击获得决心上的传奇属性*1+1点攻击检定上的增强加值。<br> 穿刺骰：若拼点成功，则此次攻击获得决心上的传奇属性*1+1点攻击检定上的增强加值。<br> 打击骰：若拼点成功，则此次攻击获得决心上的传奇属性*1+1点攻击检定上的增强加值。</p><p>当机立断<br> 类型：攻击技 <br> 等级：C<br> 派系：无 <br> 能耗：3点 <br> 成分：动作 <br> 动作：标准动作 <br> 射程：接触范围 <br> 持续：1轮 <br> 效果：<br> 使用时，立刻丢弃所有作战书页，<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 斩击骰：若拼点成功，则此次攻击获得决心上的传奇属性*3点攻击检定上的增强加值。<br> 穿刺骰：若拼点成功，则此次攻击获得决心上的传奇属性*3点攻击检定上的增强加值。<br> 打击骰：若拼点成功，则此次攻击获得决心上的传奇属性*1点攻击检定上的附加成功，额外获得决心上的传奇属性*2点攻击检定上的增强加值。</p><p>暗中调换<br> 类型：攻击技 <br> 等级：C<br> 派系：无 <br> 能耗：1点 <br> 成分：动作 <br> 动作：标准动作 <br> 射程：接触范围 <br> 持续：1轮 <br> 效果：<br> 被丢弃时，获得仅能用于使用作战书页的2AP，<br> 使用时，进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 打击骰：若拼点成功，则此次攻击命中时对敌人施加1层易损。<br> 闪避骰：若拼点成功，则获得决心上的传奇属性*1+1点闪避防御。<br>  <br> 【易损】若无专门说明，则均为强韧豁免，受易损影响的人在受到攻击时，额外受到1点严重伤害，伤害类型为力场。</p><p>解脱一击<br> 类型：攻击技 <br> 等级：B<br> 派系：无 <br> 能耗：3点 <br> 成分：动作 <br> 动作：标准动作 <br> 射程：接触范围 <br> 持续：1轮 <br> 使用时，丢弃所有作战书页，每丢弃一张作战书页本次攻击造成的伤害+1，<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 打击骰：若拼点成功，则此次攻击获得决心上的传奇属性*1+2点攻击检定上的增强加值。<br> 闪避骰：若拼点成功，则获得决心上的传奇属性*2+2点格挡防御<br> 打击骰：若拼点成功，则此次攻击额外附加6点不可豁免的流血异常点数</p><p>背水一战<br> 类型：攻击技 <br> 等级：A<br> 派系：无 <br> 能耗：4点 <br> 成分：动作 <br> 动作：标准+杂技动作 <br> 射程：接触范围 <br> 持续：1轮 <br> 效果：<br> 使用时，丢弃所有作战书页，每丢弃一张书页使该书页的骰子的威力+1。此书页一场景仅能使用一次<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 斩击骰：若拼点成功，则此次攻击造成的最终伤害增加一倍，且这次攻击获得决心上的传奇属性*1点攻击检定上的增强加值。<br> 穿刺骰：若拼点成功，则此次攻击的出目增加一半，且这次攻击获得决心上的传奇属性*1点攻击检定上的增强加值。<br> 打击骰：若拼点成功，则此次攻击造成的最终伤害增加一倍，且这次攻击获得决心上的传奇属性*1点攻击检定上的增强加值。<br> 反击打击骰：立即进入一个类招架的反击状态，无论此骰拼点成功与否，这一幕内下一次受到攻击时，招架将不再提供对于某次攻击的伤害抵销，而是在招架结算时，改为对攻击者造成等同于应得伤害抵销数目的物理严重伤害，这些伤害不能被豁免，但可以被伤害吸收等方式吸收，与招架相同，进行过一次反击后会立刻结束反击状态。并在受到攻击时立刻进行拼点，若拼点成功，则在这次反击之后额外进行一次不附带技艺的攻击，并获得1点附加成功。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
